// =============================================================================
// AG GRID MODULE REGISTRATION — SINGLE SOURCE OF TRUTH
// =============================================================================
//
// ⚠️ READ THIS BEFORE ADDING OR CHANGING ANY AG GRID FEATURE ⚠️
//
// AG Grid (v33+, this repo is on 36.x) only enables a feature if its MODULE is
// registered here. This file is the ONE place the app registers AG Grid modules.
//
// TODAY: we register `AllEnterpriseModule` — every Community + Enterprise feature
// is available, so nothing can be "missing". This is intentional and safe.
//
// IF YOU EVER TRIM TO A HAND-PICKED MODULE LIST (to shrink the bundle):
//   1. Replace `AllEnterpriseModule` below with the explicit modules you use
//      (e.g. ClientSideRowModelModule, ServerSideRowModelModule, MasterDetailModule,
//      SetFilterModule, ContextMenuModule, ColumnMenuModule, ClipboardModule,
//      CsvExportModule, ExcelExportModule, RangeSelectionModule, RowGroupingModule,
//      StatusBarModule, SideBarModule, …). Use AG Grid's "Module Selector" to derive
//      the list from the features in use.
//   2. **If you add ANY new AG Grid Enterprise feature anywhere in the app
//      (a colDef option, a gridOptions flag, a context-menu item, an export call,
//      a filter type, master/detail, row grouping, status bar, side bar, etc.)
//      you MUST add its module to the list below — otherwise the feature will
//      silently no-op in production.**
//   3. Keep development validations enabled in NON-production builds. In v36,
//      ValidationModule before any grid is created instead. It logs a console
//      warning/error naming missing modules — the safety net that turns a silent
//      prod failure into a loud dev one.
//   4. Do NOT trim without the enforcement gates (a test that fails on AG Grid
//      console errors + a per-grid feature smoke test). See
//      `docs/perf-developer-guide.md` (point #6) and `HANDOFF.md`.
//
// Registration must run before ANY grid is instantiated; importing this file for
// its side effect from the root AppModule guarantees that.
// =============================================================================

// -----------------------------------------------------------------------------
// CANDIDATE hand-picked list (audited 2026-06-22 — NOT yet active)
// -----------------------------------------------------------------------------
// A grep audit of every grid page found these FEATURES in use (high confidence):
//   • Row models: client-side (RFQ) + server-side (itemLibrary, prod_tracking, licensing)
//   • Master/Detail, Cell selection (range), Clipboard, Excel + CSV export
//   • Filters: Set, Multi, Text, Number, Date  (+ custom Angular filters)
//   • Side bar + Columns/Filters tool panels, Status bar (agg/total/selected counts)
//   • Context menu, Column menu, pagination, tooltips, agSelectCellEditor,
//     custom Angular cell renderers/editors
//   • colDefs also contain rowGroup / enablePivot / groupDisplayType / aggFunc
//     → VERIFY whether grouping/pivot is actually exercised at runtime before relying on it.
//
// The corresponding v36 module list is roughly:
//   ClientSideRowModelModule, ServerSideRowModelModule, MasterDetailModule,
//   CellSelectionModule, ClipboardModule, CsvExportModule, ExcelExportModule,
//   TextFilterModule, NumberFilterModule, DateFilterModule, SetFilterModule,
//   MultiFilterModule, CustomFilterModule, ColumnMenuModule, ContextMenuModule,
//   SideBarModule, ColumnsToolPanelModule, FiltersToolPanelModule, StatusBarModule,
//   PaginationModule, TooltipModule, RowGroupingModule, PivotModule,
//   CustomEditorModule, plus the many v33-split community API/style modules
//   (CellStyleModule, RowStyleModule, RowAutoHeightModule, ColumnAutoSizeModule,
//   RenderApiModule, RowApiModule, ColumnApiModule, EventApiModule, …) and
//   `ValidationModule` in non-prod.
//
// ⚠️ This is a CANDIDATE, not a guarantee. Deriving the exact, COMPLETE v35 module
// set by inspection is the error-prone step (a single miss = silent prod no-op).
// The reliable way to finalize it: switch to ValidationModule + this list in a dev
// build and iterate on AG Grid's console errors until clean, then lock it with a
// per-grid feature smoke test (see docs/perf-developer-guide.md #6). Until that is
// done, we deliberately keep the all-features bundle below.
// -----------------------------------------------------------------------------

import { AllEnterpriseModule, ModuleRegistry } from 'ag-grid-enterprise';
import { ValidationModule, provideGlobalGridOptions } from 'ag-grid-community';
import { environment } from '../../../environments/environment';

// -----------------------------------------------------------------------------
// THEMING — keep the legacy CSS themes (`ag-theme-alpine` + the imported
// ag-grid.css / ag-theme-alpine.css in styles.scss / angular.json).
//
// AG Grid v33+ made the new Theming API the DEFAULT. When a grid does NOT set a
// `theme`, v36 applies the Theming API and it COLLIDES with our legacy CSS —
// the rows load but render invisibly (blank grid). None of our grids set a
// `theme`, so this broke every grid app-wide after the v36 upgrade.
//
// `provideGlobalGridOptions({ theme: 'legacy' })` sets the default for ALL grids
// created afterward, so they keep using the legacy CSS themes. A grid can still
// opt into the new Theming API by setting its own `theme` (e.g. a themeQuartz
// object) in its grid options — that per-grid value overrides this default.
// Must run before any grid is instantiated; this file already guarantees that.
// -----------------------------------------------------------------------------
provideGlobalGridOptions({ theme: 'legacy' });

/**
 * The exact module set registered with AG Grid. Exported so tests / diagnostics
 * can assert what is registered (see `ModuleRegistry.isRegistered(...)` /
 * `gridApi.isModuleRegistered(...)`). When trimming, this array becomes the
 * explicit allow-list instead of the all-features bundle.
 */
export const REGISTERED_AG_GRID_MODULES = [AllEnterpriseModule];

if (!environment.production) {
  ModuleRegistry.registerModules([ValidationModule]);
}

ModuleRegistry.registerModules(REGISTERED_AG_GRID_MODULES);

import {
    themeQuartz,
    themeBalham,
    themeMaterial,
    themeAlpine,
    Theme,
    colorSchemeLightWarm,
    colorSchemeLightCold,
    colorSchemeDarkWarm,
    colorSchemeDarkBlue,
    buttonStyleQuartz,
    columnDropStyleBordered,
  } from 'ag-grid-enterprise';

  const quartzBase = themeQuartz
    .withPart(columnDropStyleBordered)
    .withPart(buttonStyleQuartz);

  // Custom Pink Theme
  const themePink: Theme = quartzBase.withParams({
    backgroundColor: "rgb(249, 245, 227)",
    foregroundColor: "rgb(126, 46, 132)",
    headerTextColor:  "rgb(204, 245, 172)",
    headerBackgroundColor: "rgb(209, 64, 129)",
    oddRowBackgroundColor: "rgba(0, 0, 0, 0.03)",
    headerColumnResizeHandleColor: "rgb(126, 46, 132)",
    selectedRowBackgroundColor: "rgba(0, 255, 0, 0.1)"
  });

  // Export all themes in one place
  export const GRID_THEME_CONFIG: Record<string, Theme> = {
    // Default themes
    quartz: quartzBase,
    balham: themeBalham,
    material: themeMaterial,
    alpine: themeAlpine,

    // Custom
    custom: themePink,

    // Color schemes
    quartzLightWarm: quartzBase.withPart(colorSchemeLightWarm),
    quartzLightCold: quartzBase.withPart(colorSchemeLightCold),
    quartzDarkWarm: quartzBase.withPart(colorSchemeDarkWarm),
    quartzDarkBlue: quartzBase.withPart(colorSchemeDarkBlue),
  };

