  letter-spacing: .06em;
  color: var(--ink-4);
}

.rp-field > span:last-child {
  font-size: 12px;
  color: var(--ink-2);
}

.mono {
  font-family: 'IBM Plex Mono', ui-monospace, monospace;
}

/* ── AG-Grid theme overrides ─────────────────────────────────────────────── */
::ng-deep {
  /* Row styling */
  .ag-theme-alpine .ag-row {
    border-bottom: 1px solid var(--line-2, #f0ece6) !important;
    background: var(--paper, #fff) !important;
    color: var(--ink, #1c1b22);
    font-family: 'Hanken Grotesk', system-ui, sans-serif;
    font-size: 13px;
    transition: background 0.08s;
  }

  .ag-theme-alpine .ag-row:hover {
    background: var(--chip, #f1eee9) !important;
  }

  .ag-theme-alpine .ag-row-selected {
    background: var(--brand-50, #ecebf6) !important;
  }

  .ag-theme-alpine .ag-row-selected::before {
    content: '';
    position: absolute;
    left: 0;
    top: 0;
    bottom: 0;
    width: 3px;
    background: var(--brand, #3f3d86);
    z-index: 1;
  }

  /* Header */
  .ag-theme-alpine .ag-header {
    background: var(--bg, #f5f3ef) !important;
    border-bottom: 1px solid var(--line, #e7e3dd) !important;
  }

  .ag-theme-alpine .ag-header-cell-label {
