  theme: Theme | "legacy" = myTheme;
  defaultColDef: ColDef = {
    editable: true,
    filter: true,
  };
  rowData!: IOlympicData[];

  constructor(private http: HttpClient) {}

  onGridReady(params: GridReadyEvent<IOlympicData>) {
    this.http
      .get<
        IOlympicData[]
      >("https://www.ag-grid.com/example-assets/olympic-winners.json")
      .subscribe((data) => (this.rowData = data));
  }
}

const myTheme = themeQuartz.withParams({
  backgroundColor: "rgb(249, 245, 227)",
  foregroundColor: "rgb(126, 46, 132)",
  headerTextColor: "rgb(204, 245, 172)",
  headerBackgroundColor: "rgb(209, 64, 129)",
  oddRowBackgroundColor: "rgb(0, 0, 0, 0.03)",
  headerColumnResizeHandleColor: "rgb(126, 46, 132)",
});
```

```interfaces.ts
export interface IOlympicData {
    athlete: string,
    age: number,
    country: string,
    year: number,
    date: string,
    sport: string,
    gold: number,
    silver: number,
    bronze: number,
    total: number
}
```

---

### CssChangeKeys

```typescript
interface CssChangeKeys {
  headerHeight: true;
  headerRowBorderWidth: true;
  rowHeight: true;
  rowBorderWidth: true;
  pinnedRowBorderWidth: true;
  cellHorizontalPadding: true;
  indentationLevel: true;
  rowGroupIndentSize: true;
  theme: true;
  listItemHeight: true;
};
```

---

The grid provides the following [Theme Parameters](ag-mcp://article/theming-parameters) to control fonts:


* `fontFamily` sets a default font for all text in the grid
* `headerFontFamily` optionally overrides the font used in the header
* `cellFontFamily` optionally overrides the font used in the data Cells


```
const myTheme = themeQuartz.withParams({
    fontFamily: 'serif',
    headerFontFamily: 'Brush Script MT',
    cellFontFamily: 'monospace',
});
```


To customise specific elements, [use CSS rules](ag-mcp://article/theming-css):


```
/* Set the subtitles within the columns tool panel in CSS */
.ag-column-drop-title {
    font-family: 'Brush Script MT';
    font-size: 1.5em;
}
```


