private bootstrapTheme(gridApi: GridApi, _destroy$: Subject<void>): void {
    // The app renders grids with AG Grid's new Theming API. `APP_GRID_THEME`
    // (a themeAlpine-based theme) is the global default set in ag-grid-modules.ts;
    // the redesign's custom grid CSS still targets the retained `.ag-theme-alpine`
    // class (now a plain styling hook) and layers on top of that base.
    //
    // Here we only need to swap in the DARK variant when the app is in dark mode
    // (Vex sets `--background-card` to '#1a202e'). The redesign's light overrides
    // are scoped to `.ag-theme-alpine` (not `-dark`), so dark grids fall back to
    // the dark base look. In light mode the global default already applies, so we
    // leave it untouched.
    const backgroundCard = getComputedStyle(document.body)
      .getPropertyValue('--background-card')
      .trim();

    if (backgroundCard === '#1a202e') {
      gridApi.setGridOption('theme', APP_GRID_THEME_DARK);
    }
  }

