import { Injectable } from '@angular/core';
import { GridApi } from 'ag-grid-enterprise';
import { Subject } from 'rxjs';
import { takeUntil } from 'rxjs/operators';
import { GridThemeEventsService } from './grid.theme.service';
import { GridSidebarEventsService } from './grid.sidebar.service';

@Injectable({ providedIn: 'root' })
export class GridUISetupService {

  constructor(
    private themeEvents: GridThemeEventsService,
    private sidebarEvents: GridSidebarEventsService
  ) {}

  /**
   * Call once inside onGridReady
   */
  bootstrap(gridApi: GridApi, destroy$: Subject<void>): void {
    this.bootstrapTheme(gridApi, destroy$);
    this.bootstrapSidebar(gridApi, destroy$);
    this.closeToolPanelDeferred(gridApi);
  }

private bootstrapTheme(gridApi: GridApi, _destroy$: Subject<void>): void {
    // The app renders grids with AG Grid's LEGACY CSS themes (`ag-theme-alpine`
    // + the imported ag-grid.css / ag-theme-alpine.css), set globally via
    // `provideGlobalGridOptions({ theme: 'legacy' })` in ag-grid-modules.ts and
    // customised in styles.scss (the redesign's grid styling targets
    // `.ag-theme-alpine`). Applying a Theming API theme object here
    // (quartz/balham/…) collides with that loaded legacy CSS — AG Grid error
    // #106 — and overrides the intended ag-theme-alpine look. So we keep every
    // grid on the legacy theme and do NOT subscribe to the theme picker.
    //
    // The toolbar grid-theme picker (toolbar-grid-theme) is therefore inert
    // until/unless the app fully migrates to the new Theming API (which would
    // mean dropping the legacy CSS + the .ag-theme-alpine custom styles).
    gridApi.setGridOption('theme', 'legacy');
  }

private bootstrapSidebar(gridApi: GridApi, destroy$: Subject<void>): void {
    const currentSidebar = this.sidebarEvents.getCurrentSidebar();
    gridApi.setGridOption('sideBar', currentSidebar);

    this.sidebarEvents.sidebarChange$
      .pipe(takeUntil(destroy$))
      .subscribe(sidebarConfig => {
        gridApi.setGridOption('sideBar', sidebarConfig);
      });
  }

  private closeToolPanelDeferred(gridApi: GridApi): void {
    setTimeout(() => {
      gridApi.closeToolPanel();
    });
  }
}

