import { Injectable } from '@angular/core';
import { HttpClient, HttpHeaders } from '@angular/common/http';
import { Observable } from 'rxjs';
import { tap } from 'rxjs/operators';
import type { GridApi } from 'ag-grid-community';
import { environment } from '../../../../environments/environment';
import type { AgGridCellNote, AgGridCellNotesMap, DesignflowGridType } from './ag-grid-cell-notes.types';

export function cellNoteKey(rowId: string, colId: string): string {
  return `${rowId}::${colId}`;
}

/** API base path for cell-notes endpoints, routed to the owning backend service. */
export function cellNotesApiBase(gridType: DesignflowGridType): string {
  switch (gridType) {
    case 'item_library':
      return `${environment.item_master}/lib`;
    case 'art_piece':
      return `${environment.item_master}/artPiece`;
    case 'license_tracking':
      return `${environment.tracking}/lic`;
    case 'production_tracking':
      return environment.tracking;
    case 'rfq':
      return environment.url;
  }
}

function parseCellNoteKey(key: string): [string, string] {
  const sep = key.indexOf('::');
  if (sep === -1) return [key, ''];
  return [key.slice(0, sep), key.slice(sep + 2)];
}

function formatTimestamp(date = new Date()): string {
  return date.toLocaleString('en-US', {
    year: 'numeric',
    month: 'short',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
  });
}

export interface AgGridCellNotesOptions {
  /** Numeric (or canonical) row id stored in grid_cell_notes.row_id. Defaults to AG Grid rowNode.id. */
  persistRowId?: (params: {
    gridRowId: string;
    rowData?: Record<string, unknown>;
  }) => string | number | null | undefined;
}

type NotesGridApi = GridApi & {
  refreshNotes?: () => void;
};

export interface DesignflowNotesDataSource {
  init?: (params: { api: NotesGridApi }) => void;
  getNote?: (params: {
    rowNode: { id: string | number | null | undefined };
    column: { getColId: () => string };
  }) => AgGridCellNote | undefined;
  setNote?: (params: {
    rowNode: { id: string | number | null | undefined; data?: Record<string, unknown> };
    column: { getColId: () => string };
    note?: AgGridCellNote;
  }) => void;
  destroy?: () => void;
}

export interface DesignflowNotesGridOptions {
  notesDataSource: DesignflowNotesDataSource;
}

export interface AgGridCellNotesHandle {
  dataSource: DesignflowNotesDataSource;
  gridOptions: DesignflowNotesGridOptions;
  preload: (
    rowIds?: string[],
    options?: { merge?: boolean; gridRowIdByPersistedId?: Record<string, string> },
  ) => Observable<AgGridCellNotesMap>;
  clear: () => void;
}

@Injectable({ providedIn: 'root' })
export class AgGridCellNotesService {
  constructor(private http: HttpClient) {}

  static refreshGridNotes(gridApi: NotesGridApi | null): void {
    if (!gridApi) return;
    if (typeof gridApi.refreshNotes === 'function') {
      gridApi.refreshNotes();
      return;
    }
    gridApi.refreshCells?.({ force: true });
  }

  createDataSource(
    gridType: DesignflowGridType,
    getCurrentUser: () => string,
    options?: AgGridCellNotesOptions,
  ): AgGridCellNotesHandle {
    const store = new Map<string, AgGridCellNote>();
    let gridApi: NotesGridApi | null = null;

    const resolvePersistRowId = (
      gridRowId: string,
      rowData?: Record<string, unknown>,
    ): string => {
      const persisted = options?.persistRowId?.({ gridRowId, rowData });
      if (persisted != null && persisted !== '') {
        return String(persisted);
      }
      return gridRowId;
    };

