export interface AgGridCellNotesHandle {
  dataSource: DesignflowNotesDataSource;
  gridOptions: DesignflowNotesGridOptions;
  preload: (
    rowIds?: string[],
    options?: { merge?: boolean; gridRowIdByPersistedId?: Record<string, string> },
  ) => Observable<AgGridCellNotesMap>;
  clear: () => void;
}

@Injectable({ providedIn: 'root' })
export class AgGridCellNotesService {
  constructor(private http: HttpClient) {}

  static refreshGridNotes(gridApi: NotesGridApi | null): void {
    if (!gridApi) return;
    if (typeof gridApi.refreshNotes === 'function') {
      gridApi.refreshNotes();
      return;
    }
    gridApi.refreshCells?.({ force: true });
  }

  createDataSource(
    gridType: DesignflowGridType,
    getCurrentUser: () => string,
    options?: AgGridCellNotesOptions,
  ): AgGridCellNotesHandle {
    const store = new Map<string, AgGridCellNote>();
    let gridApi: NotesGridApi | null = null;

    const resolvePersistRowId = (
      gridRowId: string,
      rowData?: Record<string, unknown>,
    ): string => {
      const persisted = options?.persistRowId?.({ gridRowId, rowData });
      if (persisted != null && persisted !== '') {
        return String(persisted);
      }
      return gridRowId;
    };

    const dataSource: DesignflowNotesDataSource = {
      init: (params) => {
        gridApi = params.api;
      },
      getNote: ({ rowNode, column }) => store.get(cellNoteKey(String(rowNode.id), column.getColId())),
      setNote: ({ rowNode, column, note }) => {
        const gridRowId = String(rowNode.id);
        const colId = column.getColId();
        const key = cellNoteKey(gridRowId, colId);
        const persistRowId = resolvePersistRowId(gridRowId, rowNode.data as Record<string, unknown>);

        if (note === undefined) {
          store.delete(key);
          this.persistNote(gridType, persistRowId, colId, null).subscribe();
          return;
        }

        const existing = store.get(key);
        const stamped: AgGridCellNote = {
          ...existing,
          ...note,
          author: getCurrentUser(),
          createdAt: existing?.createdAt ?? formatTimestamp(),
          updatedAt: formatTimestamp(),
        };
        store.set(key, stamped);
        this.persistNote(gridType, persistRowId, colId, stamped).subscribe();
      },
      destroy: () => {
        store.clear();
        gridApi = null;
      },
    };

    return {
      dataSource,
      preload: (rowIds?: string[], preloadOptions?: { merge?: boolean; gridRowIdByPersistedId?: Record<string, string> }) =>
        this.fetchNotes(gridType, rowIds).pipe(
          tap((notes) => {
            if (!preloadOptions?.merge) {
              store.clear();
            }
            Object.entries(notes).forEach(([key, value]) => {
              const [persistedRowId, colId] = parseCellNoteKey(key);
              const gridRowId = preloadOptions?.gridRowIdByPersistedId?.[persistedRowId] ?? persistedRowId;
              store.set(cellNoteKey(gridRowId, colId), value);
            });
            AgGridCellNotesService.refreshGridNotes(gridApi);
          }),
        ),
      clear: () => {
        store.clear();
        AgGridCellNotesService.refreshGridNotes(gridApi);
      },
      gridOptions: { notesDataSource: dataSource },
    };
  }

  private authHeaders(): HttpHeaders {
    const token = localStorage.getItem('token');
    return token ? new HttpHeaders().set('Authorization', token) : new HttpHeaders();
  }

  fetchNotes(gridType: DesignflowGridType, rowIds?: string[]): Observable<AgGridCellNotesMap> {
    return this.http.post<AgGridCellNotesMap>(
      `${cellNotesApiBase(gridType)}/getGridCellNotes`,
      { gridType, rowIds },
      { headers: this.authHeaders() },
    );
  }

  private persistNote(
    gridType: DesignflowGridType,
    rowId: string,
    colId: string,
    note: AgGridCellNote | null,
  ): Observable<{ success: boolean }> {
    return this.http.post<{ success: boolean }>(
      `${cellNotesApiBase(gridType)}/setGridCellNote`,
      { gridType, rowId, colId, note },
      { headers: this.authHeaders() },
    );
  }
}

