// Visual + console QA for the AG Grid Theming API migration on the live sandbox.
// Reads E2E_EMAIL / E2E_PASSWORD from env. Logs in, visits each grid, screenshots,
// and captures console output (flagging AG Grid theming errors/warnings).
const { chromium } = require('@playwright/test');

const BASE = 'https://alsand.designflow.app';
const OUT = process.env.OUT_DIR;
const EMAIL = process.env.E2E_EMAIL;
const PASSWORD = process.env.E2E_PASSWORD;

const GRIDS = [
  { name: 'itemLibrary', route: '/apps/itemLibrary' },
  { name: 'rfq', route: '/apps/rfq' },
  { name: 'licensing', route: '/apps/licensing-tracking' },
];

(async () => {
  if (!EMAIL || !PASSWORD) { console.error('MISSING_CREDS'); process.exit(2); }
  const browser = await chromium.launch({ headless: true });
  const ctx = await browser.newContext({ viewport: { width: 1600, height: 950 } });
  const page = await ctx.newPage();

  const allMsgs = [];
  page.on('console', m => allMsgs.push(`${m.type()}: ${m.text()}`));
  page.on('pageerror', e => allMsgs.push(`pageerror: ${e.message}`));

  // --- login ---
  await page.goto(`${BASE}/login`, { waitUntil: 'domcontentloaded' });
  await page.getByLabel('E-Mail').fill(EMAIL);
  await page.getByLabel('Password').fill(PASSWORD);
  await page.getByRole('button', { name: 'SIGN IN', exact: true }).click();
  try {
    await page.waitForURL(u => !/\/login$/.test(u.toString()), { timeout: 60000 });
  } catch {
    console.error('LOGIN_FAILED still on', page.url());
    await page.screenshot({ path: `${OUT}/login-fail.png` });
    await browser.close(); process.exit(3);
  }
  console.log('LOGIN_OK ->', page.url());

  // --- each grid ---
  for (const g of GRIDS) {
    const before = allMsgs.length;
    await page.goto(`${BASE}${g.route}`, { waitUntil: 'domcontentloaded' });
    let rows = 0, ready = false;
    try {
      await page.locator('.ag-root-wrapper').first().waitFor({ timeout: 45000 });
      await page.locator('.ag-row, .ag-overlay-loading-center').first().waitFor({ timeout: 45000 });
      ready = true;
    } catch {}
    await page.waitForTimeout(3500);
    rows = await page.locator('.ag-row').count();
    const themeClass = await page.locator('.ag-root-wrapper').first().getAttribute('class').catch(() => null);
    const shot = `${OUT}/grid-${g.name}.png`;
    await page.screenshot({ path: shot, fullPage: false });
    const gridMsgs = allMsgs.slice(before);
    const flags = gridMsgs.filter(m => /#106|#9\b|warning #|error #|Theming|initiali|legacy|license|licen[cs]e/i.test(m));
    console.log(`\n=== GRID ${g.name} (${g.route}) ===`);
    console.log(`  wrapper rendered: ${ready}  ag-row count: ${rows}`);
    console.log(`  wrapper class: ${themeClass}`);
    console.log(`  screenshot: ${shot}`);
    console.log(`  flagged console lines (${flags.length}):`);
    flags.slice(0, 15).forEach(f => console.log(`    - ${f.slice(0, 200)}`));
    if (!flags.length) console.log('    (none)');
  }

  // --- global summary of AG Grid console signals ---
  const has106 = allMsgs.some(m => /#106/.test(m));
  const has9 = allMsgs.some(m => /warning #9|#9\b/.test(m));
  const initd = allMsgs.some(m => /initiali/i.test(m));
  console.log('\n=== SUMMARY ===');
  console.log(`  error #106 present: ${has106}`);
  console.log(`  warning #9 present: ${has9}`);
  console.log(`  "initialised" seen: ${initd}`);
  console.log(`  total console lines: ${allMsgs.length}`);

  await browser.close();
})().catch(e => { console.error('SCRIPT_ERROR', e); process.exit(1); });

