const { chromium } = require('@playwright/test');
const BASE = 'https://alsand.designflow.app';
const OUT = process.env.OUT_DIR;
const EMAIL = process.env.E2E_EMAIL, PASSWORD = process.env.E2E_PASSWORD;

(async () => {
  const browser = await chromium.launch({ headless: true });
  const page = await (await browser.newContext({ viewport: { width: 1600, height: 950 } })).newPage();
  const msgs = [];
  page.on('console', m => msgs.push(`${m.type()}: ${m.text()}`));
  page.on('pageerror', e => msgs.push(`pageerror: ${e.message}`));

  await page.goto(`${BASE}/login`, { waitUntil: 'domcontentloaded' });
  await page.getByLabel('E-Mail').fill(EMAIL);
  await page.getByLabel('Password').fill(PASSWORD);
  await page.getByRole('button', { name: 'SIGN IN', exact: true }).click();
  await page.waitForURL(u => !/\/login$/.test(u.toString()), { timeout: 60000 });

  await page.goto(`${BASE}/apps/rfq`, { waitUntil: 'domcontentloaded' });
  await page.locator('.ag-root-wrapper').first().waitFor({ timeout: 45000 });
  // poll until rows load (up to 75s)
  let rows = 0;
  for (let i = 0; i < 25; i++) {
    rows = await page.locator('.ag-row').count();
    if (rows > 0) break;
    await page.waitForTimeout(3000);
  }
  await page.waitForTimeout(1500);
  rows = await page.locator('.ag-row').count();
  await page.screenshot({ path: `${OUT}/grid-rfq-loaded.png`, fullPage: false });
  console.log('RFQ ag-row count after wait:', rows);
  const flags = msgs.filter(m => /#106|warning #9\b|Theming|initiali/i.test(m));
  console.log('theming-relevant console lines:', flags.length ? flags.join('\n') : '(none)');
  console.log('error #106 present:', msgs.some(m => /#106/.test(m)));
  await browser.close();
})().catch(e => { console.error('ERR', e); process.exit(1); });

